  market_pips_description: { ar:'احسب عدد النقاط والربح أو الخسارة بين سعر الدخول وسعر الخروج.', en:'Calculate pips and profit or loss between entry and exit prices.', fr:'Calculez les pips et le gain ou la perte entre les prix d’entrée et de sortie.' },
